 1→import { detectMime } from "../media/mime.js";
 2→import { type SavedMedia, saveMediaBuffer } from "../media/store.js";
 3→
 4→export type TelegramFileInfo = {
 5→  file_id: string;
 6→  file_unique_id?: string;
 7→  file_size?: number;
 8→  file_path?: string;
 9→};
10→
11→export async function getTelegramFile(token: string, fileId: string): Promise<TelegramFileInfo> {
12→  const res = await fetch(
13→    `https://api.telegram.org/bot${token}/getFile?file_id=${encodeURIComponent(fileId)}`,
14→  );
15→  if (!res.ok) {
16→    throw new Error(`getFile failed: ${res.status} ${res.statusText}`);
17→  }
18→  const json = (await res.json()) as { ok: boolean; result?: TelegramFileInfo };
19→  if (!json.ok || !json.result?.file_path) {
20→    throw new Error("getFile returned no file_path");
21→  }
22→  return json.result;
23→}
24→
25→export async function downloadTelegramFile(
26→  token: string,
27→  info: TelegramFileInfo,
28→  maxBytes?: number,
29→): Promise<SavedMedia> {
30→  if (!info.file_path) throw new Error("file_path missing");
31→  const url = `https://api.telegram.org/file/bot${token}/${info.file_path}`;
32→  const res = await fetch(url);
33→  if (!res.ok || !res.body) {
34→    throw new Error(`Failed to download telegram file: HTTP ${res.status}`);
35→  }
36→  const array = Buffer.from(await res.arrayBuffer());
37→  const mime = await detectMime({
38→    buffer: array,
39→    headerMime: res.headers.get("content-type"),
40→    filePath: info.file_path,
41→  });
42→  // save with inbound subdir
43→  const saved = await saveMediaBuffer(array, mime, "inbound", maxBytes);
44→  // Ensure extension matches mime if possible
45→  if (!saved.contentType && mime) saved.contentType = mime;
46→  return saved;
47→}
