  1→import fs from "node:fs";
  2→import path from "node:path";
  3→import os from "node:os";
  4→import { messagingApi } from "@line/bot-sdk";
  5→import { logVerbose } from "../globals.js";
  6→
  7→interface DownloadResult {
  8→  path: string;
  9→  contentType?: string;
 10→  size: number;
 11→}
 12→
 13→export async function downloadLineMedia(
 14→  messageId: string,
 15→  channelAccessToken: string,
 16→  maxBytes = 10 * 1024 * 1024,
 17→): Promise<DownloadResult> {
 18→  const client = new messagingApi.MessagingApiBlobClient({
 19→    channelAccessToken,
 20→  });
 21→
 22→  const response = await client.getMessageContent(messageId);
 23→
 24→  // response is a Readable stream
 25→  const chunks: Buffer[] = [];
 26→  let totalSize = 0;
 27→
 28→  for await (const chunk of response as AsyncIterable<Buffer>) {
 29→    totalSize += chunk.length;
 30→    if (totalSize > maxBytes) {
 31→      throw new Error(`Media exceeds ${Math.round(maxBytes / (1024 * 1024))}MB limit`);
 32→    }
 33→    chunks.push(chunk);
 34→  }
 35→
 36→  const buffer = Buffer.concat(chunks);
 37→
 38→  // Determine content type from magic bytes
 39→  const contentType = detectContentType(buffer);
 40→  const ext = getExtensionForContentType(contentType);
 41→
 42→  // Write to temp file
 43→  const tempDir = os.tmpdir();
 44→  const fileName = `line-media-${messageId}-${Date.now()}${ext}`;
 45→  const filePath = path.join(tempDir, fileName);
 46→
 47→  await fs.promises.writeFile(filePath, buffer);
 48→
 49→  logVerbose(`line: downloaded media ${messageId} to ${filePath} (${buffer.length} bytes)`);
 50→
 51→  return {
 52→    path: filePath,
 53→    contentType,
 54→    size: buffer.length,
 55→  };
 56→}
 57→
 58→function detectContentType(buffer: Buffer): string {
 59→  // Check magic bytes
 60→  if (buffer.length >= 2) {
 61→    // JPEG
 62→    if (buffer[0] === 0xff && buffer[1] === 0xd8) {
 63→      return "image/jpeg";
 64→    }
 65→    // PNG
 66→    if (buffer[0] === 0x89 && buffer[1] === 0x50 && buffer[2] === 0x4e && buffer[3] === 0x47) {
 67→      return "image/png";
 68→    }
 69→    // GIF
 70→    if (buffer[0] === 0x47 && buffer[1] === 0x49 && buffer[2] === 0x46) {
 71→      return "image/gif";
 72→    }
 73→    // WebP
 74→    if (
 75→      buffer[0] === 0x52 &&
 76→      buffer[1] === 0x49 &&
 77→      buffer[2] === 0x46 &&
 78→      buffer[3] === 0x46 &&
 79→      buffer[8] === 0x57 &&
 80→      buffer[9] === 0x45 &&
 81→      buffer[10] === 0x42 &&
 82→      buffer[11] === 0x50
 83→    ) {
 84→      return "image/webp";
 85→    }
 86→    // MP4
 87→    if (buffer[4] === 0x66 && buffer[5] === 0x74 && buffer[6] === 0x79 && buffer[7] === 0x70) {
 88→      return "video/mp4";
 89→    }
 90→    // M4A/AAC
 91→    if (buffer[0] === 0x00 && buffer[1] === 0x00 && buffer[2] === 0x00) {
 92→      if (buffer[4] === 0x66 && buffer[5] === 0x74 && buffer[6] === 0x79 && buffer[7] === 0x70) {
 93→        return "audio/mp4";
 94→      }
 95→    }
 96→  }
 97→
 98→  return "application/octet-stream";
 99→}
100→
101→function getExtensionForContentType(contentType: string): string {
102→  switch (contentType) {
103→    case "image/jpeg":
104→      return ".jpg";
105→    case "image/png":
106→      return ".png";
107→    case "image/gif":
108→      return ".gif";
109→    case "image/webp":
110→      return ".webp";
111→    case "video/mp4":
112→      return ".mp4";
113→    case "audio/mp4":
114→      return ".m4a";
115→    case "audio/mpeg":
116→      return ".mp3";
117→    default:
118→      return ".bin";
119→  }
120→}
