 22→function buildTempDownloadPath(fileName: string): string {
 23→  const id = crypto.randomUUID();
 24→  const safeName = fileName.trim() ? fileName.trim() : "download.bin";
 25→  return path.join("/tmp/moltbot/downloads", `${id}-${safeName}`);
 26→}
