 28→function createPageDownloadWaiter(page: Page, timeoutMs: number) {
 29→  let done = false;
 30→  let timer: NodeJS.Timeout | undefined;
 31→  let handler: ((download: unknown) => void) | undefined;
 32→
 33→  const cleanup = () => {
 34→    if (timer) clearTimeout(timer);
 35→    timer = undefined;
 36→    if (handler) {
 37→      page.off("download", handler as never);
 38→      handler = undefined;
 39→    }
 40→  };
 41→
 42→  const promise = new Promise<unknown>((resolve, reject) => {
 43→    handler = (download: unknown) => {
 44→      if (done) return;
 45→      done = true;
 46→      cleanup();
 47→      resolve(download);
 48→    };
 49→
 50→    page.on("download", handler as never);
 51→    timer = setTimeout(() => {
 52→      if (done) return;
 53→      done = true;
 54→      cleanup();
 55→      reject(new Error("Timeout waiting for download"));
 56→    }, timeoutMs);
 57→  });
 58→
 59→  return {
 60→    promise,
 61→    cancel: () => {
 62→      if (done) return;
 63→      done = true;
 64→      cleanup();
 65→    },
 66→  };
 67→}
