 69→export async function armFileUploadViaPlaywright(opts: {
 70→  cdpUrl: string;
 71→  targetId?: string;
 72→  paths?: string[];
 73→  timeoutMs?: number;
 74→}): Promise<void> {
 75→  const page = await getPageForTargetId(opts);
 76→  const state = ensurePageState(page);
 77→  const timeout = Math.max(500, Math.min(120_000, opts.timeoutMs ?? 120_000));
 78→
 79→  state.armIdUpload = bumpUploadArmId();
 80→  const armId = state.armIdUpload;
 81→
 82→  void page
 83→    .waitForEvent("filechooser", { timeout })
 84→    .then(async (fileChooser) => {
 85→      if (state.armIdUpload !== armId) return;
 86→      if (!opts.paths?.length) {
 87→        // Playwright removed `FileChooser.cancel()`; best-effort close the chooser instead.
 88→        try {
 89→          await page.keyboard.press("Escape");
 90→        } catch {
 91→          // Best-effort.
 92→        }
 93→        return;
 94→      }
 95→      await fileChooser.setFiles(opts.paths);
 96→      try {
 97→        const input =
 98→          typeof fileChooser.element === "function"
 99→            ? await Promise.resolve(fileChooser.element())
100→            : null;
101→        if (input) {
102→          await input.evaluate((el) => {
103→            el.dispatchEvent(new Event("input", { bubbles: true }));
104→            el.dispatchEvent(new Event("change", { bubbles: true }));
105→          });
106→        }
107→      } catch {
108→        // Best-effort for sites that don't react to setFiles alone.
109→      }
110→    })
111→    .catch(() => {
112→      // Ignore timeouts; the chooser may never appear.
113→    });
114→}
