116→export async function armDialogViaPlaywright(opts: {
117→  cdpUrl: string;
118→  targetId?: string;
119→  accept: boolean;
120→  promptText?: string;
121→  timeoutMs?: number;
122→}): Promise<void> {
123→  const page = await getPageForTargetId(opts);
124→  const state = ensurePageState(page);
125→  const timeout = normalizeTimeoutMs(opts.timeoutMs, 120_000);
126→
127→  state.armIdDialog = bumpDialogArmId();
128→  const armId = state.armIdDialog;
129→
130→  void page
131→    .waitForEvent("dialog", { timeout })
132→    .then(async (dialog) => {
133→      if (state.armIdDialog !== armId) return;
134→      if (opts.accept) await dialog.accept(opts.promptText);
135→      else await dialog.dismiss();
136→    })
137→    .catch(() => {
138→      // Ignore timeouts; the dialog may never appear.
139→    });
140→}
