142→export async function waitForDownloadViaPlaywright(opts: {
143→  cdpUrl: string;
144→  targetId?: string;
145→  path?: string;
146→  timeoutMs?: number;
147→}): Promise<{
148→  url: string;
149→  suggestedFilename: string;
150→  path: string;
151→}> {
152→  const page = await getPageForTargetId(opts);
153→  const state = ensurePageState(page);
154→  const timeout = normalizeTimeoutMs(opts.timeoutMs, 120_000);
155→
156→  state.armIdDownload = bumpDownloadArmId();
157→  const armId = state.armIdDownload;
158→
159→  const waiter = createPageDownloadWaiter(page, timeout);
160→  try {
161→    const download = (await waiter.promise) as {
162→      url?: () => string;
163→      suggestedFilename?: () => string;
164→      saveAs?: (outPath: string) => Promise<void>;
165→    };
166→    if (state.armIdDownload !== armId) {
167→      throw new Error("Download was superseded by another waiter");
168→    }
169→    const suggested = download.suggestedFilename?.() || "download.bin";
170→    const outPath = opts.path?.trim() || buildTempDownloadPath(suggested);
171→    await fs.mkdir(path.dirname(outPath), { recursive: true });
172→    await download.saveAs?.(outPath);
173→    return {
174→      url: download.url?.() || "",
175→      suggestedFilename: suggested,
176→      path: path.resolve(outPath),
177→    };
178→  } catch (err) {
179→    waiter.cancel();
180→    throw err;
181→  }
182→}
