184→export async function downloadViaPlaywright(opts: {
185→  cdpUrl: string;
186→  targetId?: string;
187→  ref: string;
188→  path: string;
189→  timeoutMs?: number;
190→}): Promise<{
191→  url: string;
192→  suggestedFilename: string;
193→  path: string;
194→}> {
195→  const page = await getPageForTargetId(opts);
196→  const state = ensurePageState(page);
197→  restoreRoleRefsForTarget({ cdpUrl: opts.cdpUrl, targetId: opts.targetId, page });
198→  const timeout = normalizeTimeoutMs(opts.timeoutMs, 120_000);
199→
200→  const ref = requireRef(opts.ref);
201→  const outPath = String(opts.path ?? "").trim();
202→  if (!outPath) throw new Error("path is required");
203→
204→  state.armIdDownload = bumpDownloadArmId();
205→  const armId = state.armIdDownload;
206→
207→  const waiter = createPageDownloadWaiter(page, timeout);
208→  try {
209→    const locator = refLocator(page, ref);
210→    try {
211→      await locator.click({ timeout });
212→    } catch (err) {
213→      throw toAIFriendlyError(err, ref);
214→    }
215→
216→    const download = (await waiter.promise) as {
217→      url?: () => string;
218→      suggestedFilename?: () => string;
219→      saveAs?: (outPath: string) => Promise<void>;
220→    };
221→    if (state.armIdDownload !== armId) {
222→      throw new Error("Download was superseded by another waiter");
223→    }
224→    const suggested = download.suggestedFilename?.() || "download.bin";
225→    await fs.mkdir(path.dirname(outPath), { recursive: true });
226→    await download.saveAs?.(outPath);
227→    return {
228→      url: download.url?.() || "",
229→      suggestedFilename: suggested,
230→      path: path.resolve(outPath),
231→    };
232→  } catch (err) {
233→    waiter.cancel();
234→    throw err;
235→  }
236→}
